import{_ as e,c as o,o as t,a1 as d}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Funcionalidades Avançadas","description":"Aprenda a configuração avançada do Clawdbot, incluindo configuração de modelos de IA, colaboração de múltiplos agentes, automação de navegador, ferramentas de execução de comandos, ferramentas de busca na Web, interface visual Canvas, ativação de voz e TTS, sistema de memória, tarefas agendadas Cron, plataforma de habilidades, sandbox de segurança e Gateway remoto.","frontmatter":{"title":"Funcionalidades Avançadas","sidebarTitle":"Desbloqueie Superpoderes de IA","subtitle":"Funcionalidades Avançadas","description":"Aprenda a configuração avançada do Clawdbot, incluindo configuração de modelos de IA, colaboração de múltiplos agentes, automação de navegador, ferramentas de execução de comandos, ferramentas de busca na Web, interface visual Canvas, ativação de voz e TTS, sistema de memória, tarefas agendadas Cron, plataforma de habilidades, sandbox de segurança e Gateway remoto.","prerequisite":["/pt/moltbot/moltbot/start/getting-started","/pt/moltbot/moltbot/start/gateway-startup"],"order":185},"headers":[],"relativePath":"pt/moltbot/moltbot/advanced/index.md","filePath":"pt/moltbot/moltbot/advanced/index.md"}'),i={name:"pt/moltbot/moltbot/advanced/index.md"};function r(s,a,n,l,c,m){return t(),o("div",null,[...a[0]||(a[0]=[d('<h1 id="funcionalidades-avancadas" tabindex="-1">Funcionalidades Avançadas <a class="header-anchor" href="#funcionalidades-avancadas" aria-label="Permalink to &quot;Funcionalidades Avançadas&quot;">​</a></h1><h2 id="visao-geral-do-capitulo" tabindex="-1">Visão Geral do Capítulo <a class="header-anchor" href="#visao-geral-do-capitulo" aria-label="Permalink to &quot;Visão Geral do Capítulo&quot;">​</a></h2><p>Este capítulo aprofunda as funcionalidades avançadas do Clawdbot, ajudando você a aproveitar ao máximo o poderoso assistente de IA. Desde a configuração de modelos de IA e colaboração de múltiplos agentes, até automação de navegador, sistema de memória e funcionalidades de voz, você pode escolher o que aprender de acordo com suas necessidades.</p><div class="info custom-block"><p class="custom-block-title">Pré-requisitos</p><p>Antes de estudar este capítulo, complete o seguinte:</p><ul><li><a href="./../../start/getting-started/">Início Rápido</a></li><li><a href="./../../start/gateway-startup/">Iniciar o Gateway</a></li></ul></div><h2 id="caminhos-de-aprendizado" tabindex="-1">Caminhos de Aprendizado <a class="header-anchor" href="#caminhos-de-aprendizado" aria-label="Permalink to &quot;Caminhos de Aprendizado&quot;">​</a></h2><p>De acordo com suas necessidades, você pode escolher diferentes caminhos de aprendizado:</p><h3 id="🚀-caminho-de-inicio-rapido-recomendado-para-iniciantes" tabindex="-1">🚀 Caminho de Início Rápido (Recomendado para Iniciantes) <a class="header-anchor" href="#🚀-caminho-de-inicio-rapido-recomendado-para-iniciantes" aria-label="Permalink to &quot;🚀 Caminho de Início Rápido (Recomendado para Iniciantes)&quot;">​</a></h3><ol><li><a href="./models-auth/">Configuração de Modelos e Autenticação de IA</a> - Configure seus modelos de IA favoritos</li><li><a href="./tools-exec/">Ferramentas de Execução de Comandos e Aprovação</a> - Permita que a IA execute comandos com segurança</li><li><a href="./tools-web/">Ferramentas de Busca e Coleta na Web</a> - Estenda a capacidade de aquisição de conhecimento da IA</li></ol><h3 id="🤖-caminho-de-extensao-de-capacidades-de-ia" tabindex="-1">🤖 Caminho de Extensão de Capacidades de IA <a class="header-anchor" href="#🤖-caminho-de-extensao-de-capacidades-de-ia" aria-label="Permalink to &quot;🤖 Caminho de Extensão de Capacidades de IA&quot;">​</a></h3><ol><li><a href="./session-management/">Gerenciamento de Sessões e Múltiplos Agentes</a> - Entenda o mecanismo de colaboração de IA</li><li><a href="./memory-system/">Sistema de Memória e Busca Vetorial</a> - Permita que a IA se lembre de informações importantes</li><li><a href="./skills-platform/">Plataforma de Habilidades e ClawdHub</a> - Use e compartilhe pacotes de habilidades</li></ol><h3 id="🔧-caminho-de-ferramentas-de-automacao" tabindex="-1">🔧 Caminho de Ferramentas de Automação <a class="header-anchor" href="#🔧-caminho-de-ferramentas-de-automacao" aria-label="Permalink to &quot;🔧 Caminho de Ferramentas de Automação&quot;">​</a></h3><ol><li><a href="./tools-browser/">Ferramentas de Automação de Navegador</a> - Automação de operações na Web</li><li><a href="./cron-automation/">Tarefas Agendadas Cron e Webhook</a> - Tarefas agendadas e gatilhos de eventos</li><li><a href="./remote-gateway/">Gateway Remoto e Tailscale</a> - Acesso remoto ao seu assistente de IA</li></ol><h3 id="🎨-caminho-de-experiencia-de-interacao" tabindex="-1">🎨 Caminho de Experiência de Interação <a class="header-anchor" href="#🎨-caminho-de-experiencia-de-interacao" aria-label="Permalink to &quot;🎨 Caminho de Experiência de Interação&quot;">​</a></h3><ol><li><a href="./canvas/">Interface Visual Canvas e A2UI</a> - Interface interativa visual</li><li><a href="./voice-tts/">Ativação de Voz e Texto para Voz</a> - Funcionalidades de interação por voz</li></ol><h3 id="🔒-caminho-de-seguranca-e-implantacao" tabindex="-1">🔒 Caminho de Segurança e Implantação <a class="header-anchor" href="#🔒-caminho-de-seguranca-e-implantacao" aria-label="Permalink to &quot;🔒 Caminho de Segurança e Implantação&quot;">​</a></h3><ol><li><a href="./security-sandbox/">Segurança e Isolamento Sandbox</a> - Entenda o mecanismo de segurança</li><li><a href="./remote-gateway/">Gateway Remoto e Tailscale</a> - Acesso remoto seguro</li></ol><h2 id="navegacao-de-subpaginas" tabindex="-1">Navegação de Subpáginas <a class="header-anchor" href="#navegacao-de-subpaginas" aria-label="Permalink to &quot;Navegação de Subpáginas&quot;">​</a></h2><h3 id="configuracoes-principais" tabindex="-1">Configurações Principais <a class="header-anchor" href="#configuracoes-principais" aria-label="Permalink to &quot;Configurações Principais&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tópico</th><th>Descrição</th><th>Tempo Estimado</th></tr></thead><tbody><tr><td><a href="./models-auth/">Configuração de Modelos e Autenticação de IA</a></td><td>Configure múltiplos provedores de modelos de IA e métodos de autenticação como Anthropic, OpenAI, OpenRouter, Ollama, etc.</td><td>15 minutos</td></tr><tr><td><a href="./session-management/">Gerenciamento de Sessões e Múltiplos Agentes</a></td><td>Aprenda conceitos principais como modelo de sessão, isolamento de sessão, colaboração de sub-agentes, compressão de contexto, etc.</td><td>20 minutos</td></tr></tbody></table><h3 id="sistema-de-ferramentas" tabindex="-1">Sistema de Ferramentas <a class="header-anchor" href="#sistema-de-ferramentas" aria-label="Permalink to &quot;Sistema de Ferramentas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tópico</th><th>Descrição</th><th>Tempo Estimado</th></tr></thead><tbody><tr><td><a href="./tools-browser/">Ferramentas de Automação de Navegador</a></td><td>Use ferramentas de navegador para automação de páginas da Web, capturas de tela, operações de formulários, etc.</td><td>25 minutos</td></tr><tr><td><a href="./tools-exec/">Ferramentas de Execução de Comandos e Aprovação</a></td><td>Configure e use ferramentas exec, entenda mecanismo de aprovação de segurança e controle de permissões</td><td>15 minutos</td></tr><tr><td><a href="./tools-web/">Ferramentas de Busca e Coleta na Web</a></td><td>Use ferramentas web_search e web_fetch para busca na Web e coleta de conteúdo</td><td>20 minutos</td></tr></tbody></table><h3 id="experiencia-de-interacao" tabindex="-1">Experiência de Interação <a class="header-anchor" href="#experiencia-de-interacao" aria-label="Permalink to &quot;Experiência de Interação&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tópico</th><th>Descrição</th><th>Tempo Estimado</th></tr></thead><tbody><tr><td><a href="./canvas/">Interface Visual Canvas e A2UI</a></td><td>Entenda mecanismo de push Canvas A2UI, operações de interface visual e interfaces personalizadas</td><td>20 minutos</td></tr><tr><td><a href="./voice-tts/">Ativação de Voz e Texto para Voz</a></td><td>Configure Voice Wake, Talk Mode e provedores TTS para implementar interação por voz</td><td>15 minutos</td></tr></tbody></table><h3 id="extensao-de-inteligencia" tabindex="-1">Extensão de Inteligência <a class="header-anchor" href="#extensao-de-inteligencia" aria-label="Permalink to &quot;Extensão de Inteligência&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tópico</th><th>Descrição</th><th>Tempo Estimado</th></tr></thead><tbody><tr><td><a href="./memory-system/">Sistema de Memória e Busca Vetorial</a></td><td>Configure e use sistema de memória (SQLite-vec, FTS5, busca híbrida)</td><td>25 minutos</td></tr><tr><td><a href="./skills-platform/">Plataforma de Habilidades e ClawdHub</a></td><td>Entenda sistema de habilidades, habilidades Bundled/Managed/Workspace, integração ClawdHub</td><td>20 minutos</td></tr></tbody></table><h3 id="automacao-e-implantacao" tabindex="-1">Automação e Implantação <a class="header-anchor" href="#automacao-e-implantacao" aria-label="Permalink to &quot;Automação e Implantação&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tópico</th><th>Descrição</th><th>Tempo Estimado</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Tarefas Agendadas Cron e Webhook</a></td><td>Configure tarefas agendadas, gatilhos Webhook, Pub/Sub Gmail e outras funcionalidades de automação</td><td>20 minutos</td></tr><tr><td><a href="./remote-gateway/">Gateway Remoto e Tailscale</a></td><td>Acesse Gateway remotamente via Tailscale Serve/Funnel ou túnel SSH</td><td>15 minutos</td></tr></tbody></table><h3 id="mecanismos-de-seguranca" tabindex="-1">Mecanismos de Segurança <a class="header-anchor" href="#mecanismos-de-seguranca" aria-label="Permalink to &quot;Mecanismos de Segurança&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tópico</th><th>Descrição</th><th>Tempo Estimado</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">Segurança e Isolamento Sandbox</a></td><td>Entenda modelo de segurança, controle de permissões de ferramentas, isolamento Sandbox, implantação em Docker</td><td>20 minutos</td></tr></tbody></table><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após completar o estudo deste capítulo, você pode:</p><ol><li><strong>Estudo aprofundado</strong> - Consulte <a href="./../../faq/troubleshooting/">Solução de Problemas</a> para resolver problemas encontrados</li><li><strong>Entender implantação</strong> - Consulte <a href="./../../appendix/deployment/">Opções de Implantação</a> para implantar o Clawdbot em ambiente de produção</li><li><strong>Desenvolver extensões</strong> - Consulte <a href="./../../appendix/development/">Guia de Desenvolvimento</a> para aprender como desenvolver plug-ins e contribuir com código</li><li><strong>Ver configuração</strong> - Consulte <a href="./../../appendix/config-reference/">Referência Completa de Configuração</a> para conhecer todas as opções de configuração</li></ol><div class="tip custom-block"><p class="custom-block-title">Sugestão de Aprendizado</p><p>Sugere-se que você escolha o caminho de aprendizado de acordo com suas necessidades reais. Se não tiver certeza por onde começar, pode seguir o &quot;Caminho de Início Rápido&quot; para estudar gradualmente, e outros tópicos podem ser estudados aprofundadamente quando necessário.</p></div>',33)])])}const p=e(i,[["render",r]]);export{h as __pageData,p as default};
